package cmd

import (
	"context"
	"fmt"
	"os"
	"os/exec"
	"path/filepath"
	"regexp"
	"strings"
	"time"

	"github.com/spf13/cobra"
)

var versionCommitPattern = regexp.MustCompile(`(?m)^Commit:\s*(\S+)\s*$`)

func (f *CommandFactory) buildWorkBinaryRefreshCheck(cmd *cobra.Command, projectRoot, targetBeadID string) func(context.Context) (bool, error) {
	if targetBeadID != "" {
		return nil
	}
	if !workBinaryRefreshEnabled(os.Args) {
		return nil
	}
	currentCommit := normalizeVersionCommit(f.Commit)
	if currentCommit == "" {
		return nil
	}
	return func(ctx context.Context) (bool, error) {
		exe := resolveReplacementDDXPath()
		checkCtx, cancel := context.WithTimeout(ctx, 5*time.Second)
		defer cancel()
		installedCommit, err := installedDDXCommit(checkCtx, exe)
		if err != nil {
			return false, err
		}
		if !shouldRefreshDDXBinary(currentCommit, installedCommit) {
			return false, nil
		}
		wd, wdErr := os.Getwd()
		if wdErr != nil || wd == "" {
			wd = projectRoot
		}
		args := append([]string(nil), os.Args[1:]...)
		_, _ = fmt.Fprintf(cmd.ErrOrStderr(), "ddx work: detected installed ddx binary changed (current commit %s, installed commit %s); starting replacement worker and exiting\n", currentCommit, installedCommit)
		if err := startReplacementDDX(exe, args, wd); err != nil {
			return false, err
		}
		return true, nil
	}
}

func workBinaryRefreshEnabled(args []string) bool {
	if len(args) == 0 {
		return false
	}
	return filepath.Base(args[0]) == "ddx"
}

func installedDDXCommit(ctx context.Context, exe string) (string, error) {
	out, err := exec.CommandContext(ctx, exe, "version", "--no-check").CombinedOutput()
	if err != nil {
		return "", fmt.Errorf("probe installed ddx version: %w", err)
	}
	return parseDDXVersionCommit(string(out)), nil
}

func parseDDXVersionCommit(output string) string {
	matches := versionCommitPattern.FindStringSubmatch(output)
	if len(matches) != 2 {
		return ""
	}
	return normalizeVersionCommit(matches[1])
}

func normalizeVersionCommit(commit string) string {
	commit = strings.TrimSpace(commit)
	switch strings.ToLower(commit) {
	case "", "unknown", "dev", "none":
		return ""
	default:
		return commit
	}
}

func shouldRefreshDDXBinary(currentCommit, installedCommit string) bool {
	currentCommit = normalizeVersionCommit(currentCommit)
	installedCommit = normalizeVersionCommit(installedCommit)
	if currentCommit == "" || installedCommit == "" {
		return false
	}
	if currentCommit == installedCommit {
		return false
	}
	if len(currentCommit) >= 7 && len(installedCommit) >= 7 {
		if strings.HasPrefix(currentCommit, installedCommit) || strings.HasPrefix(installedCommit, currentCommit) {
			return false
		}
	}
	return true
}

func resolveReplacementDDXPath() string {
	if len(os.Args) > 0 && os.Args[0] != "" {
		if path, err := exec.LookPath(os.Args[0]); err == nil {
			return path
		}
	}
	if path, err := os.Executable(); err == nil {
		return path
	}
	if len(os.Args) > 0 {
		return os.Args[0]
	}
	return "ddx"
}

func startReplacementDDX(exe string, args []string, dir string) error {
	replacement := exec.Command(exe, args...)
	replacement.Dir = dir
	replacement.Env = os.Environ()
	replacement.Stdin = os.Stdin
	replacement.Stdout = os.Stdout
	replacement.Stderr = os.Stderr
	return replacement.Start()
}

	overrides := config.CLIOverrides{
		Assignee: resolveClaimAssignee(),
		Harness:  harness,
		Model:    model,
		Provider: provider,
		Profile:  profile,
		Effort:   effort,
	}
	rcfg, err := config.LoadAndResolve(projectRoot, overrides)
	if err != nil {
		return fmt.Errorf("load resolved config: %w", err)
	}
	if _, err := resourceChecker.Check(cmd.Context()); err != nil {
		if resErr, ok := err.(*agent.ResourceExhaustedError); ok && resErr != nil {
			fmt.Fprintln(cmd.ErrOrStderr(), resErr.Error())
		}
		return &ExitError{Code: tryExitFailed, Message: err.Error()}
	}

	cliLandingOps := agent.RealLandingGitOps{}
	var qualityRunner agent.AgentRunner
	if f.AgentRunnerOverride != nil {
		qualityRunner = f.AgentRunnerOverride
	}
	lintHook := agent.NewPreDispatchLintHook(projectRoot, store, rcfg, nil, qualityRunner)
	triageHook := agent.NewPostAttemptTriageHook(projectRoot, store, rcfg, nil, qualityRunner, nil)
	proseHook := f.proseEvidenceHookOverride
	if proseHook == nil {
		proseHook = agent.NewDefaultProseEvidenceHook(agent.ProseEvidenceConfig{
			ProjectRoot: projectRoot,
			Events:      bead.NewStore(ddxroot.JoinProject(projectRoot)),
			Actor:       resolveClaimAssignee(),
			Source:      "ddx try",
		})
	}
	result, runErr := worker.Run(cmd.Context(), rcfg, agent.ExecuteBeadLoopRuntime{
		Mode:                  executeloop.ModeOnce,
		Log:                   cmd.OutOrStdout(),
		EventSink:             loopSink,
		WorkerID:              resolveClaimAssignee(),
		ProjectRoot:           projectRoot,
		ResourceChecker:       resourceChecker,
		SessionID:             loopSessionID,
		PreClaimHook:          buildCLIPreClaimHook(projectRoot, cliLandingOps),
		PreDispatchLintHook:   lintHook,
		PostAttemptTriageHook: triageHook,
		ProseEvidenceHook:     proseHook,
		NoReview:              noReview,
	})
	if runErr != nil {
		if (errors.Is(runErr, context.Canceled) || errors.Is(runErr, context.DeadlineExceeded)) && result != nil && len(result.Results) > 0 {
			writeTryResult(cmd.OutOrStdout(), result.Results[0])
		}
		return runErr
	}

	// Report outcome.
	if result.NoReadyWork {
		// Bead was not in the execution-ready queue even after pre-flight passed.
		// This can happen if a heartbeat re-appeared just before claim, making it
		// not stale-enough for reclaim. Surface a clear message.
		fmt.Fprintf(cmd.ErrOrStderr(), "bead is not execution-ready (it may be actively claimed by another worker): %s\n", beadID)
		return &ExitError{Code: tryExitFailed, Message: ""}
	}

	if len(result.Results) == 0 {
		return &ExitError{Code: tryExitFailed, Message: ""}
	}
	report := result.Results[0]
	writeTryResult(cmd.OutOrStdout(), report)
	if intent := escalation.ParseExecutionHint(target); intent.Source == escalation.ExecutionIntentSourceBeadHint && intent.InferredPowerClass != "" {
		fmt.Fprintf(cmd.OutOrStdout(), "routing intent: difficulty=%s powerClass=%s source=%s\n", intent.EstimatedDifficulty, intent.InferredPowerClass, intent.Source)
	}

	return tryExitCodeForStatus(report.Status)
}

func writeTryResult(w io.Writer, report agent.ExecuteBeadReport) {
	fmt.Fprintf(w, "\nbead: %s\nstatus: %s\n", report.BeadID, report.Status)
	if report.Detail != "" {
		fmt.Fprintf(w, "detail: %s\n", report.Detail)
	}
	if report.ResultRev != "" {
		fmt.Fprintf(w, "result_rev: %s\n", report.ResultRev)
	}
	if report.PreserveRef != "" {
		fmt.Fprintf(w, "preserve_ref: %s\n", report.PreserveRef)
	}
}

