}

func writeProjectVersion(t *testing.T, workDir, version string) {
	t.Helper()
	require.NoError(t, os.MkdirAll(filepath.Join(workDir, ddxroot.DirName), 0o755))
	require.NoError(t, os.WriteFile(
		filepath.Join(workDir, ddxroot.DirName, "versions.yaml"),
		[]byte("ddx_version: \""+version+"\"\n"),
		0o644,
	))
}

func seedStaleSourceCheckout(t *testing.T) (projectRoot, buildSHA, headSHA string) {
	t.Helper()

	projectRoot = minimalProjectDir(t)
	require.NoError(t, os.WriteFile(filepath.Join(projectRoot, "README.md"), []byte("# ddx\n"), 0o644))

	runGit(t, projectRoot, "init")
	runGit(t, projectRoot, "config", "user.email", "test@example.com")
	runGit(t, projectRoot, "config", "user.name", "Test User")
	runGit(t, projectRoot, "remote", "add", "origin", "git@github.com:DocumentDrivenDX/ddx.git")
	runGit(t, projectRoot, "add", ".")
	runGit(t, projectRoot, "commit", "-m", "initial source state")
	buildSHA = gitOutput(t, projectRoot, "rev-parse", "HEAD")

	require.NoError(t, os.WriteFile(filepath.Join(projectRoot, "README.md"), []byte("# ddx\n\nsource ahead\n"), 0o644))
	runGit(t, projectRoot, "add", "README.md")
	runGit(t, projectRoot, "commit", "-m", "source ahead of installed binary")
	headSHA = gitOutput(t, projectRoot, "rev-parse", "HEAD")

	return projectRoot, buildSHA, headSHA
}

func runGit(t *testing.T, dir string, args ...string) {
	t.Helper()
	cmd := exec.Command("git", args...)
	cmd.Dir = dir
	cmd.Env = gitpkg.CleanEnv()
	out, err := cmd.CombinedOutput()
	require.NoError(t, err, "git %v failed: %s", args, string(out))
}

func gitOutput(t *testing.T, dir string, args ...string) string {
	t.Helper()
	cmd := exec.Command("git", args...)
	cmd.Dir = dir
	cmd.Env = gitpkg.CleanEnv()
	out, err := cmd.Output()
	require.NoError(t, err, "git %v failed", args)
	return string(bytesTrimSpace(out))
}

func bytesTrimSpace(b []byte) []byte {
	return []byte(string(b[:len(b)]))
}

// non-zero and writes "bead has unmet dependencies: <list>" to stderr.
func TestTry_BeadUnmetDeps(t *testing.T) {
	env := NewTestEnvironment(t)
	store := bead.NewStore(env.Dir + "/.ddx")
	require.NoError(t, store.Init())

	// Create the dependency first (store validates dep references exist).
	require.NoError(t, store.Create(&bead.Bead{
		ID:     "dep-bead-001",
		Title:  "Dependency bead (still open)",
		Status: bead.StatusOpen,
	}))
	require.NoError(t, store.Create(&bead.Bead{
		ID:           "target-bead-001",
		Title:        "Target bead with dep",
		Dependencies: []bead.Dependency{{IssueID: "target-bead-001", DependsOnID: "dep-bead-001", Type: "blocks"}},
	}))

	root := NewCommandFactory(env.Dir).NewRootCommand()
	out, err := executeCommand(root, "try", "target-bead-001")
	assert.Error(t, err, "ddx try with unmet deps must exit non-zero")
